SELECT ROW_NUMBER() OVER(ORDER BY STOR_SEQ) AS BOARD_NUM, STOR_SEQ, STOR_CD, STOR_NM, STOR_DIV, TEL_NO, STICKER_EXP, TRT_WRKJOB, HANDL_PROD, ZIPCD, STOR_ROADN_ADR, STOR_ARNO_ADR, DTL_ADR, LATIT_VAL, LNGIT_VAL, MARK_IMG, STOR_ITR, SHOW_YN, CRET_ID, AMD_ID, CRET_DT, AMD_DT, NFC_ABLE_VAL, NFC_DISABLE_VAL, STOR_SORT FROM NMCP_STOR_ADM_BAS WHERE 1=1
AND STOR_DIV = #{schStorDiv}
AND LOWER(STOR_NM) LIKE '%'||LOWER(#{searchStr})||'%' AND LOWER(STOR_ROADN_ADR) LIKE '%'||LOWER(#{searchStr})||'%' ORDER BY STOR_SORT DESC ,STOR_NM ASC
